-- ESTUDIAR · Fase E-2 (INGLÉS) — teoría de sesión + ejemplos con audio + prueba.
-- Llena el hueco que dejó E-1 en la estructura tab→nivel→tema→teoría. Contenido
-- autorado por profesores nativos + guardas deterministas + revisión adversarial.
-- SOLO inglés (course en). NO toca motor FSRS, economía, gating, certificación
-- ni los otros 5 idiomas. El quiz es FORMATIVO: califica con el grader tolerante
-- (jz_grade, mig 177) y NO paga XP/oro ni escribe user_item_attempts.

create table if not exists public.study_theory (
  id uuid primary key default gen_random_uuid(),
  course_id uuid not null references public.courses(id) on delete cascade,
  unit_order int not null,
  cefr_level text not null,
  title text not null,
  summary text not null,
  sections jsonb not null default '[]'::jsonb,
  examples jsonb not null default '[]'::jsonb,
  pitfalls jsonb not null default '[]'::jsonb,
  quiz jsonb not null default '[]'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (course_id, unit_order)
);

-- RLS ON sin política: el quiz lleva las respuestas → SOLO lo leen las funciones
-- SECURITY DEFINER de abajo (mismo patrón que lesson_vocab/stories.questions).
alter table public.study_theory enable row level security;
revoke all on public.study_theory from anon, authenticated;


-- ── Datos (idempotente por (course_id, unit_order)) ────────────────────────
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 1, 'A1', 'Saludos y presentarte', 'Aprende a saludar y decir quién eres en inglés. Al terminar dirás tu nombre, tu edad y de dónde eres sin errores.', '[{"heading": "Saluda y di tu nombre", "body": "En inglés el sujeto casi nunca se omite (la excepción son las órdenes: Open the door). En español dices \"Soy Ana\", pero en inglés siempre necesitas I: \"I am Ana\".", "bullets": ["Hello / Hi = saludo para cualquier momento.", "Good morning (hasta el mediodía) · Good afternoon (hasta ~18h).", "Good evening (a partir de ahí). Ojo: Good night es para despedirse.", "I am Ana. = Soy Ana.", "My name is Ana. = Me llamo Ana."]}, {"heading": "Tu edad: be, no have", "body": "El español usa tener para la edad; el inglés usa be. Dices \"I am 20\" o \"I am 20 years old\". Nunca uses have aquí. Y recuerda: el sujeto I siempre aparece.", "bullets": ["I am 20. = Tengo 20 años.", "She is 25 years old. = Ella tiene 25 años.", "Nunca digas: I have 20 years.", "How old are you? = ¿Cuántos años tienes?"]}, {"heading": "A o an: manda el sonido", "body": "Usa a antes de sonido de consonante y an antes de sonido de vocal. Es el sonido, no la letra. Sirve para decir tu trabajo: en inglés el trabajo lleva artículo, en español no.", "bullets": ["a teacher, a student, a doctor.", "an engineer, an artist, an actor.", "I am a nurse. = Soy enfermera.", "Español: Soy médico. Inglés: I am a doctor."]}]'::jsonb, '[{"en": "Hello! My name is Ana.", "es": "¡Hola! Me llamo Ana.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0dff0634-f44e-5adb-bdee-330dae513eba.mp3"}, {"en": "I am 20 years old.", "es": "Tengo 20 años.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/fae11375-3c2b-578b-975e-737f19dd55bb.mp3"}, {"en": "I am a student.", "es": "Soy estudiante.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/fda737a7-ba11-53e8-b5f2-17e1b41c3deb.mp3"}, {"en": "She is an engineer.", "es": "Ella es ingeniera.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/aa1495aa-208f-539d-91f0-56abab5b9f6c.mp3"}]'::jsonb, '[{"title": "No digas \"I have 20 years\"", "body": "La edad en inglés va con el verbo be, no con have. Correcto: I am 20 (years old). El error viene de traducir \"tengo\" literalmente."}, {"title": "No olvides el sujeto", "body": "En español puedes decir \"Soy Ana\", pero en inglés la frase necesita el sujeto: I am Ana. Sin I la oración está incompleta."}, {"title": "El trabajo lleva a / an", "body": "En español dices \"Soy profesor\"; en inglés siempre hay artículo: I am a teacher. Con sonido de vocal usa an: I am an engineer."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta para decir tu edad:", "options": ["I am 20 years old.", "I have 20 years.", "I have 20 years old."], "answer": "I am 20 years old.", "id": "u1q1"}, {"type": "multiple_choice", "prompt": "¿Qué artículo corresponde a la palabra engineer?", "options": ["an engineer", "a engineer", "the engineer"], "answer": "an engineer", "id": "u1q2"}, {"type": "cloze", "prompt": "Completa con el verbo be. Traducción: Soy Ana.", "text": "I ___ Ana.", "answer": "am", "accepted": ["am", "''m"], "id": "u1q3"}, {"type": "cloze", "prompt": "Completa con el artículo correcto. Traducción: Soy estudiante.", "text": "I am ___ student.", "answer": "a", "accepted": ["a"], "id": "u1q4"}, {"type": "multiple_choice", "prompt": "¿Cuál oración está completa y correcta en inglés?", "options": ["Am Ana.", "I am Ana.", "Is Ana am."], "answer": "I am Ana.", "id": "u1q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 2, 'A1', 'Números, edad y de dónde eres', 'Aprende a decir tu edad y de dónde eres usando el verbo be. Después hablarás de la gente con el posesivo ''s y con his/her.', '[{"heading": "Números y edad: la edad va con BE", "body": "Los números que más usarás: one, two, three… ten, eleven, twelve, twenty, twenty-five. Para la edad, el inglés usa el verbo be, no have: How old are you? I''m twenty-five (years old).", "bullets": ["How old are you? → I''m 25 (years old).", "13-19 terminan en -teen; 20-90 en -ty.", "Compuestos con guion: twenty-one, thirty-five.", "Nunca digas \"I have 25 years\"."]}, {"heading": "¿De dónde eres? Origen y nacionalidad", "body": "Pregunta con be: Where are you from? Responde: I''m from Peru. El país lleva from; la nacionalidad no: I''m Peruvian. Países y nacionalidades van siempre con mayúscula, aunque en español se escriban en minúscula.", "bullets": ["I''m from Spain. = I''m Spanish.", "Mayúscula siempre: Peruvian, Mexican, Spanish, English.", "Él o ella: Where is he from? He''s from Chile.", "No mezcles: \"I''m from Peruvian\" es incorrecto."]}, {"heading": "De quién hablas: ''s, his y her", "body": "Para decir de quién es algo, primero va el dueño: María''s brother (el hermano de María). Con personas no uses of. Y \"su\" es his (de él) o her (de ella), según quién sea el dueño.", "bullets": ["Dueño + ''s + cosa: Ana''s phone.", "His = de él; her = de ella.", "Mira al dueño: María → her brother.", "Plurales en -s: my parents'' house; pero children''s toys."]}]'::jsonb, '[{"en": "How old are you? I''m twenty-five years old.", "es": "¿Cuántos años tienes? Tengo veinticinco años.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/5929fba7-418f-5bc6-9c14-aeb6c3895680.mp3"}, {"en": "Where are you from? I''m from Peru. I''m Peruvian.", "es": "¿De dónde eres? Soy de Perú. Soy peruano.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/61c9b7ec-a16a-5d45-b2cb-5dd5a484f55a.mp3"}, {"en": "This is María''s brother. His name is Diego.", "es": "Este es el hermano de María. Su nombre es Diego.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3d7c8ab8-40ff-58f3-85dd-ef93e6730508.mp3"}, {"en": "My sister is twelve. Her friends are Mexican.", "es": "Mi hermana tiene doce años. Sus amigas son mexicanas.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e72e3703-9c76-53d2-83c1-4013d5612d3f.mp3"}]'::jsonb, '[{"title": "Decir la edad con \"have\"", "body": "En español tienes años; en inglés los eres. No digas \"I have twenty-five years\": di I''m twenty-five (years old)."}, {"title": "Escribir la nacionalidad en minúscula", "body": "En español escribimos \"peruano, español\". En inglés siempre llevan mayúscula: Peruvian, Spanish, Mexican, English."}, {"title": "Decir \"the brother of María\"", "body": "Con personas no se usa \"of\". La estructura correcta es dueño + ''s + cosa: María''s brother."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta de decir \"Tengo veinticinco años\".", "options": ["I''m twenty-five years old", "I have twenty-five years", "I have twenty-five years old"], "answer": "I''m twenty-five years old", "id": "u2q1"}, {"type": "cloze", "prompt": "Completa la frase. Estás diciendo que eres de Perú.", "text": "I''m ___ Peru.", "answer": "from", "accepted": ["from"], "id": "u2q2"}, {"type": "cloze", "prompt": "Completa la pregunta. Quieres saber la edad de otra persona.", "text": "How ___ are you?", "answer": "old", "accepted": ["old"], "id": "u2q3"}, {"type": "multiple_choice", "prompt": "María habla de su hermano. Elige la frase correcta.", "options": ["Her brother is Peruvian", "His brother is Peruvian", "She brother is Peruvian"], "answer": "Her brother is Peruvian", "id": "u2q4"}, {"type": "cloze", "prompt": "Completa la frase. Hablas de ti mismo: tienes once años.", "text": "I ___ eleven years old.", "answer": "am", "accepted": ["am", "''m"], "id": "u2q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 3, 'A1', 'La familia y las personas', 'Aquí vas a hablar de tu familia y de lo que hace cada persona: la -s de he/she/it, dónde van always/usually/never y cómo negar con don''t / doesn''t.', '[{"heading": "La -s de he/she/it", "body": "En presente simple, el verbo cambia solo con he, she e it: se le añade -s. Con I, you, we y they el verbo no cambia. Es la marca más importante de este tema.", "bullets": ["I work · you work · we work · they work", "He works · she works · it works", "go → goes, do → does, watch → watches", "have → has (irregular): She has two brothers."]}, {"heading": "Adverbios de frecuencia: dónde van", "body": "always, usually, sometimes y never van ANTES del verbo normal, pero DESPUÉS del verbo be. Con eso te basta en A1; más adelante verás otras posiciones.", "bullets": ["Antes del verbo: She always helps my mother.", "Después de be: My father is never late.", "never ya es negativo: no uses don''t con never.", "Orden: sujeto + adverbio + verbo."]}, {"heading": "Negar con don''t / doesn''t", "body": "Para negar usamos don''t con I, you, we, they; y doesn''t con he, she, it. Muy importante: después de doesn''t el verbo pierde la -s y va en forma base.", "bullets": ["I don''t live here. / They don''t work on Sunday.", "He doesn''t live here. (NO: doesn''t lives)", "doesn''t = does not · don''t = do not", "Con be se niega distinto: She isn''t my sister."]}]'::jsonb, '[{"en": "My sister works in a hospital.", "es": "Mi hermana trabaja en un hospital.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/25011751-787c-5af9-a191-0b05795c64e4.mp3"}, {"en": "My brother doesn''t have children.", "es": "Mi hermano no tiene hijos.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8aa3bf3c-f290-5495-8afa-6dc5ad365dc8.mp3"}, {"en": "My parents always have dinner at eight.", "es": "Mis padres siempre cenan a las ocho.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d98e20c8-e926-5e40-a60c-65bd18fb0478.mp3"}, {"en": "My grandmother is never tired.", "es": "Mi abuela nunca está cansada.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/dd3bc016-9d54-50de-b803-e009efa7849f.mp3"}]'::jsonb, '[{"title": "\"He doesn''t works\" — doble marca", "body": "La -s ya está en doesn''t, así que el verbo va en forma base. Di: He doesn''t work on Saturday. Nunca: He doesn''t works."}, {"title": "Olvidar la -s en he/she/it", "body": "En español el verbo cambia solo; en inglés la marca es la -s. Di: She lives in Lima (no: She live in Lima)."}, {"title": "Poner el adverbio en el lugar del español", "body": "No digas: She helps always my mother. El adverbio va antes del verbo: She always helps my mother."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta del verbo con ''my father''.", "options": ["My father work in a bank.", "My father works in a bank.", "My father working in a bank."], "answer": "My father works in a bank.", "id": "u3q1"}, {"type": "multiple_choice", "prompt": "¿Dónde va el adverbio de frecuencia? Elige la frase correcta.", "options": ["My mother usually cooks on Sunday.", "My mother cooks usually on Sunday.", "Usually my mother cooks she on Sunday."], "answer": "My mother usually cooks on Sunday.", "id": "u3q2"}, {"type": "cloze", "prompt": "Completa con la forma correcta del verbo ''live'' para ''she''.", "text": "She ___ in Madrid with her family.", "answer": "lives", "accepted": ["lives"], "id": "u3q3"}, {"type": "cloze", "prompt": "Niega la frase: usa la forma negativa correcta para ''my brother''.", "text": "My brother ___ have a car.", "answer": "doesn''t", "accepted": ["doesn''t", "does not"], "id": "u3q4"}, {"type": "cloze", "prompt": "Niega la frase con el sujeto ''my parents''.", "text": "My parents ___ work on Sunday.", "answer": "don''t", "accepted": ["don''t", "do not"], "id": "u3q5"}, {"type": "multiple_choice", "prompt": "Elige la frase correcta con el verbo be.", "options": ["My father is never late.", "My father never is late.", "My father is late never."], "answer": "My father is never late.", "id": "u3q6"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 4, 'A1', 'Comida y bebida / en el café', 'Aprende a pedir comida y bebida en inglés con naturalidad. Vas a dominar cuándo usar ''a'', ''some'' y ''any'', y cómo contar (o no contar) lo que pides.', '[{"heading": "¿Se puede contar? Ahí está la clave", "body": "En inglés hay palabras que se cuentan (one apple, two apples) y otras que no (water, rice, money). Las que NO se cuentan nunca llevan ''a'' y nunca van en plural.", "bullets": ["Contables: an apple, two sandwiches, three eggs.", "Incontables: water, milk, bread, rice, sugar.", "Incontables: sin plural (nunca ''waters'', ''breads'').", "Para medir: a glass of water, a cup of tea.", "En un café, pedir por tazas sí cuenta: a coffee, a tea."]}, {"heading": "Some y any: la pareja inseparable", "body": "Usa ''some'' en frases afirmativas y ''any'' en preguntas y negativas. Ambos significan ''algo de'' o ''algunos'', y muchas veces en español ni se traducen.", "bullets": ["Afirmativo: I want some coffee.", "Pregunta: Do you have any milk?", "Negativo: We don''t have any sugar.", "Excepción útil: pedir con ''some'' → Can I have some water?"]}, {"heading": "Much y many", "body": "Usa ''many'' con contables y ''much'' con incontables, sobre todo en preguntas y negativas. En frases afirmativas suena más natural decir ''a lot of''.", "bullets": ["How many sandwiches? (contable)", "How much sugar? (incontable)", "''a lot of'' sirve para los dos casos.", "Extra de pronunciación: ''th'' con la lengua entre los dientes: three, thanks."]}]'::jsonb, '[{"en": "I''d like some water, please.", "es": "Quisiera un poco de agua, por favor.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/97a553fc-56d6-5c44-baff-50765ef9ee0c.mp3"}, {"en": "Can I have a coffee and two sandwiches?", "es": "¿Me pone un café y dos sándwiches?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f3485eea-b91d-5dfe-b4a7-fee08d5bbf4e.mp3"}, {"en": "Sorry, we don''t have any milk today.", "es": "Lo siento, hoy no tenemos leche.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/63b6d20a-04c0-5083-beba-686ddd362e26.mp3"}, {"en": "How much is a cup of tea?", "es": "¿Cuánto cuesta una taza de té?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7888b28c-3f80-5092-84fc-f90daa83131b.mp3"}]'::jsonb, '[{"title": "No digas ''a water'' para el líquido", "body": "El agua no se cuenta: ''a water'' es incorrecto en clase de A1. Di ''some water'' o ''a glass of water''. Lo mismo con ''a bread'' → ''some bread''."}, {"title": "''Any'' en negativas, no ''some''", "body": "Los hispanohablantes dicen ''We don''t have some sugar'' copiando el español. Lo correcto es ''We don''t have any sugar''."}, {"title": "''Much'' y ''many'' no son intercambiables", "body": "''How much apples?'' es incorrecto porque las manzanas se cuentan. Di ''How many apples?'' y reserva ''much'' para agua, azúcar, dinero."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la opción correcta para pedir agua en un café.", "options": ["I''d like some water, please.", "I''d like a water, please.", "I''d like waters, please."], "answer": "I''d like some water, please.", "id": "u4q1"}, {"type": "cloze", "prompt": "Completa la pregunta. Regla general de esta unidad: en preguntas usamos any.", "text": "Do we have ___ milk?", "answer": "any", "accepted": ["any"], "id": "u4q2"}, {"type": "cloze", "prompt": "Completa la frase negativa.", "text": "Sorry, we don''t have ___ sugar.", "answer": "any", "accepted": ["any"], "id": "u4q3"}, {"type": "multiple_choice", "prompt": "¿Cuál pregunta es correcta con un sustantivo contable?", "options": ["How many sandwiches do you want?", "How much sandwiches do you want?", "How many sandwich do you want?"], "answer": "How many sandwiches do you want?", "id": "u4q4"}, {"type": "cloze", "prompt": "Completa con much o many.", "text": "How ___ coffee do you drink every day?", "answer": "much", "accepted": ["much"], "id": "u4q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 5, 'A1', 'El día y la hora', 'Aprende a decir la hora, los días y los meses en inglés, y a elegir bien entre at, on e in. También repasas there is / there are con horarios.', '[{"heading": "At, on, in: el truco del tamaño", "body": "Piensa en el tamaño del tiempo. At es para la hora exacta. On es para un día o una fecha. In es para periodos largos: meses, estaciones y años.", "bullets": ["at + hora: at seven, at noon", "on + día o fecha: on Monday, on May 3rd", "in + mes, estación o año: in July, in 2026", "in + parte del día: in the morning, in the evening", "Excepción: at night (nunca in night)", "De menor a mayor: at → on → in"]}, {"heading": "Cómo decir la hora", "body": "Lo más fácil y natural es decir los números: seven thirty. También puedes usar o''clock para las horas en punto, y half past o quarter para las medias y los cuartos.", "bullets": ["6:00 → six o''clock", "6:15 → six fifteen / quarter past six", "6:30 → six thirty / half past six", "6:45 → six forty-five / quarter to seven"]}, {"heading": "Días, meses y horarios", "body": "Los días y los meses siempre van en mayúscula en inglés. Con there is y there are puedes hablar de lo que hay en un horario o en un día.", "bullets": ["Mayúscula siempre: Monday, Friday, June", "There is a class at ten.", "There are two classes on Tuesday.", "Días de la semana: Monday → Sunday"]}]'::jsonb, '[{"en": "The class starts at nine.", "es": "La clase empieza a las nueve.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8300fdc4-ca4e-5c3a-8abf-b42519395ddd.mp3"}, {"en": "I work on Monday and Friday.", "es": "Trabajo el lunes y el viernes.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/fb262fbe-c194-557a-8c8b-feb5b3b79c34.mp3"}, {"en": "My birthday is in July.", "es": "Mi cumpleaños es en julio.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/65314602-7aec-597a-9af1-0990309ac3d8.mp3"}, {"en": "There are three meetings on Wednesday.", "es": "Hay tres reuniones el miércoles.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/77e3780e-f225-5521-86e4-8447113ade0e.mp3"}]'::jsonb, '[{"title": "No uses in con la hora", "body": "Con una hora exacta el inglés usa at, no in. Incorrecto: I get up in seven. Correcto: I get up at seven. Ojo: con partes del día sí se usa in (in the morning, in the afternoon) y con la noche se dice at night."}, {"title": "Los días no llevan the", "body": "\"El lunes\" no se traduce con the. Incorrecto: I study the Monday. Correcto: I study on Monday."}, {"title": "Días y meses en mayúscula", "body": "En español se escriben en minúscula, pero en inglés no. Incorrecto: monday, july. Correcto: Monday, July."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la preposición correcta: The film starts ___ eight.", "options": ["at", "on", "in"], "answer": "at", "id": "u5q1"}, {"type": "multiple_choice", "prompt": "Elige la opción correcta para 7:30.", "options": ["seven thirty", "thirty seven", "seven and thirty"], "answer": "seven thirty", "id": "u5q2"}, {"type": "cloze", "prompt": "Completa con la preposición correcta (día de la semana).", "text": "I work ___ Monday.", "answer": "on", "accepted": ["on"], "id": "u5q3"}, {"type": "cloze", "prompt": "Completa con la preposición correcta (mes).", "text": "My birthday is ___ July.", "answer": "in", "accepted": ["in"], "id": "u5q4"}, {"type": "cloze", "prompt": "Completa con there is o there are (una clase).", "text": "___ a class at ten.", "answer": "There is", "accepted": ["There is", "There''s"], "id": "u5q5"}]'::jsonb)
