values ('20000000-0000-0000-0000-000000000001', 6, 'A1', 'Lugares y direcciones', 'Vas a describir lugares de tu ciudad y decir qué se puede hacer en ellos. Practicarás can, el adjetivo antes del sustantivo y like + -ing.', '[{"heading": "El adjetivo va DELANTE del lugar", "body": "En inglés el adjetivo va DELANTE del sustantivo al que describe: a big park, nunca a park big. Sí puede ir después del verbo be: The park is big. El adjetivo tampoco cambia en plural: siempre big, sin -s.", "bullets": ["a small shop, a new school, an old church", "Nunca: a shop small.", "Plural: two big parks (big sin -s)."]}, {"heading": "Can para decir qué se puede hacer", "body": "Can tiene la misma forma para todos: I can, she can, they can. Después va el verbo solo, sin to y sin -s. La negación es can''t para todos.", "bullets": ["You can buy bread here.", "She can walk to the station.", "Nunca: she cans, she can to go.", "Negativo: We can''t park here."]}, {"heading": "Dónde está: in, on, next to", "body": "Usa in para ciudades y espacios cerrados, on para calles, y next to para algo que está al lado. Con estas tres preposiciones ya das direcciones básicas.", "bullets": ["in the park, in London", "on Green Street", "next to the bank, near the school"]}]'::jsonb, '[{"en": "There is a big park next to my house.", "es": "Hay un parque grande al lado de mi casa.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/305ee9dd-9bc4-5831-80a3-9e821c435a8d.mp3"}, {"en": "You can buy coffee in that small shop.", "es": "Puedes comprar café en esa tienda pequeña.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/951846fa-37d7-5a1e-bc05-9dba03578c81.mp3"}, {"en": "I like walking in the old city centre.", "es": "Me gusta caminar por el centro antiguo de la ciudad.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3feb78db-14a3-5408-9899-2aa390ec2aa0.mp3"}, {"en": "The bank is on Green Street, next to the school.", "es": "El banco está en la calle Green, al lado de la escuela.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f46087b9-46e3-5ef7-a3e8-1db7faa27e15.mp3"}]'::jsonb, '[{"title": "El adjetivo detrás del sustantivo", "body": "Traducir «un parque grande» como a park big es incorrecto. En inglés el adjetivo va primero: a big park."}, {"title": "Poner -s o to con can", "body": "Nunca digas she cans swim ni she can to swim. Can no lleva -s y el verbo que sigue va sin to: she can swim."}, {"title": "Después de like no uses el verbo pelado", "body": "No digas I like walk. Con hobbies lo más común es -ing: I like walking. También es correcto I like to walk; en este curso practicamos la forma -ing."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la frase correcta en inglés.", "options": ["There is a big park near my house.", "There is a park big near my house.", "There is a bigs park near my house."], "answer": "There is a big park near my house.", "id": "u6q1"}, {"type": "cloze", "prompt": "Completa con la forma correcta de can.", "text": "She ___ swim very well.", "answer": "can", "accepted": ["can"], "id": "u6q2"}, {"type": "multiple_choice", "prompt": "¿Cuál es la forma correcta después de can?", "options": ["You can visit the museum today.", "You can to visit the museum today.", "You cans visit the museum today."], "answer": "You can visit the museum today.", "id": "u6q3"}, {"type": "cloze", "prompt": "Completa con la preposición correcta (la calle).", "text": "The bank is ___ Green Street.", "answer": "on", "accepted": ["on"], "id": "u6q4"}, {"type": "cloze", "prompt": "Completa con la forma correcta del verbo walk.", "text": "I like ___ in the park.", "answer": "walking", "accepted": ["walking", "to walk"], "id": "u6q5"}]'::jsonb)
