values ('20000000-0000-0000-0000-000000000001', 7, 'A2', 'El pasado: lo que hice', 'Aprende a contar lo que hiciste ayer: verbos regulares con -ed, los irregulares más usados y el negativo con didn''t.', '[{"heading": "Regulares: añade -ed", "body": "Para hablar del pasado, la mayoría de verbos solo añaden -ed. La forma es igual para todas las personas: I, you, he, she, we, they. No cambia nada más.", "bullets": ["work → worked, play → played", "Igual para todas las personas: he worked", "Termina en -e: like → liked", "Consonante + y: study → studied", "Vocal + consonante final: stop → stopped, plan → planned"]}, {"heading": "Irregulares en grupos", "body": "Algunos verbos muy comunes no usan -ed. Apréndelos en grupos pequeños, no en listas largas. Repite cada grupo en voz alta con una frase corta.", "bullets": ["Vocal cambia: give→gave, come→came", "Terminan en -ought: buy→bought, think→thought", "Totalmente distintos: go→went, see→saw", "No cambian: put→put, cut→cut"]}, {"heading": "En negativo, sin pasado doble", "body": "En negativo usas didn''t y el verbo vuelve a su forma base. El pasado ya está en did, así que el verbo no lo repite. Lo mismo pasa en las preguntas con did.", "bullets": ["I didn''t go (no *didn''t went*)", "She didn''t work yesterday", "Preguntas: Did you see it?", "Respuesta corta: Yes, I did / No, I didn''t"]}]'::jsonb, '[{"en": "I went to the cinema yesterday.", "es": "Fui al cine ayer.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b706deaf-4539-56d4-a58d-8e08735f3703.mp3"}, {"en": "We watched a film and cooked dinner.", "es": "Vimos una película y cocinamos la cena.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/61180702-a631-5016-8000-be517125dae0.mp3"}, {"en": "She didn''t come to the party last night.", "es": "Ella no vino a la fiesta anoche.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7a4b608c-a58d-57c9-8d68-2bfd853850ed.mp3"}, {"en": "Did you buy the tickets on Monday?", "es": "¿Compraste las entradas el lunes?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/13a14e06-54e2-5e38-8701-ab12c003f200.mp3"}]'::jsonb, '[{"title": "Pasado doble en el negativo", "body": "Muchos dicen *I didn''t went*. Después de didn''t el verbo va en forma base: I didn''t go. Lo mismo en preguntas: Did you go? (no *Did you went?*)."}, {"title": "Poner -ed a un verbo irregular", "body": "No existen *goed*, *seed* ni *buyed*. Los irregulares tienen su propia forma: went, saw, bought. Repásalos en grupos pequeños."}, {"title": "La -ed no siempre suena igual", "body": "Se pronuncia /t/ en worked, /d/ en played y /ɪd/ solo después de t o d: wanted, needed. Es decir, la -ed suena como sílaba aparte SOLO en verbos como wanted o needed; en worked o played no se añade sílaba."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta del pasado de \"go\".", "options": ["went", "goed", "gone"], "answer": "went", "id": "u7q1"}, {"type": "multiple_choice", "prompt": "¿Cuál frase negativa es correcta?", "options": ["I didn''t go to work.", "I didn''t went to work.", "I not went to work."], "answer": "I didn''t go to work.", "id": "u7q2"}, {"type": "cloze", "prompt": "Completa con el pasado de \"watch\".", "text": "We ___ a great film last night.", "answer": "watched", "accepted": ["watched"], "id": "u7q3"}, {"type": "cloze", "prompt": "Completa el negativo: ella no vino a la fiesta.", "text": "She ___ come to the party.", "answer": "didn''t", "accepted": ["didn''t", "did not", "didn´t"], "id": "u7q4"}, {"type": "multiple_choice", "prompt": "¿En cuál de estos verbos la terminación -ed suena /ɪd/?", "options": ["wanted", "played", "worked"], "answer": "wanted", "id": "u7q5"}]'::jsonb)
