insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 9, 'A2', 'De viaje', 'Aprende a moverte por una ciudad en inglés: decir a dónde vas, pedir direcciones con cortesía y entender en qué planta está algo.', '[{"heading": "1. ''Go to'' + lugar, pero ''go home'' sin ''to''", "body": "Para decir a dónde vas usas ''go to'' + el lugar. Hay tres excepciones muy comunes que NO llevan ''to'': home, here y there. Es un error casi automático del hispanohablante, así que memorízalas como un bloque.", "bullets": ["go to the airport / to the station / to Madrid", "go home, come here, go there → sin ''to''", "Con ''get'' funciona igual: get home, get to the hotel", "Sin destino, ''to'' desaparece: Let''s go!"]}, {"heading": "2. Pedir direcciones con cortesía", "body": "Empieza siempre con ''Excuse me''. Después usa una fórmula suave: ''Could you tell me...?'' o ''Is there... near here?''. Con ''Could you tell me where...'' el orden es normal, no de pregunta: where the station is.", "bullets": ["Excuse me, could you tell me where the bank is?", "Excuse me, is there a pharmacy near here?", "How do I get to the museum?", "Cierra siempre con ''Thank you'' o ''Thanks a lot''."]}, {"heading": "3. Las plantas: ''ground floor''", "body": "En inglés británico la planta baja es ''the ground floor''. El ''first floor'' es nuestro primer piso, es decir, el de arriba. Usa ''on'' con las plantas: on the second floor.", "bullets": ["ground floor = planta baja", "first floor = primer piso en inglés británico (en EE. UU., planta baja).", "Siempre ''on the ... floor'', nunca ''in''", "Take the lift / the stairs to the third floor."]}]'::jsonb, '[{"en": "Excuse me, could you tell me where the station is?", "es": "Disculpe, ¿podría decirme dónde está la estación?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/70a3f673-2f94-554c-b643-b81e3d93c624.mp3"}, {"en": "I need to go to the airport, and then I want to go home.", "es": "Necesito ir al aeropuerto y luego quiero ir a casa.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/8f2789ab-2c37-5717-b046-6085e6d3a333.mp3"}, {"en": "Excuse me, is there a supermarket near here?", "es": "Disculpe, ¿hay un supermercado cerca de aquí?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7ef3dbb0-4b2c-545b-bc49-35f29a8a216d.mp3"}, {"en": "The tickets are on the ground floor, next to the exit.", "es": "Los billetes están en la planta baja, al lado de la salida.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3adf520b-42ca-5540-8e4c-8254923dad5f.mp3"}]'::jsonb, '[{"title": "\"I go to home\" ❌", "body": "''Home'' nunca lleva ''to'' después de go/come/get. Di ''I go home'' o ''I''m going home''. Lo mismo con here y there: ''come here'', no ''come to here''."}, {"title": "\"Where is the station?\" dentro de una pregunta cortés ❌", "body": "Tras ''Could you tell me'' el verbo va detrás del sujeto: ''Could you tell me where the station is?'', no ''...where is the station?''."}, {"title": "Confundir ''first floor'' con la planta baja ❌", "body": "En inglés británico la planta baja es ''the ground floor'' y ''first floor'' es un piso más arriba. En inglés americano se dice ''first floor'' para la planta baja. Y recuerda: ''on the first floor'', no ''in''."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la opción correcta: «Voy a casa».", "options": ["I''m going to home.", "I''m going home.", "I''m going at home."], "answer": "I''m going home.", "id": "u9q1"}, {"type": "cloze", "prompt": "Completa con la preposición correcta.", "text": "I want to go ___ the airport.", "answer": "to", "accepted": ["to"], "id": "u9q2"}, {"type": "multiple_choice", "prompt": "Estás en la calle y quieres preguntar dónde está el museo. Elige la forma más cortés y correcta.", "options": ["Excuse me, could you tell me where the museum is?", "Excuse me, could you tell me where is the museum?", "Excuse me, you tell me the museum where?"], "answer": "Excuse me, could you tell me where the museum is?", "id": "u9q3"}, {"type": "cloze", "prompt": "Completa: la recepción está en la planta baja.", "text": "Reception is on the ___ floor.", "answer": "ground", "accepted": ["ground"], "id": "u9q4"}, {"type": "cloze", "prompt": "Completa la pregunta cortés con un verbo modal.", "text": "Excuse me, ___ you tell me where the bus stop is?", "answer": "could", "accepted": ["could", "can", "would"], "id": "u9q5"}]'::jsonb)
