  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 10, 'A2', 'Comer fuera y comprar', 'Vas a dominar los comparativos en inglés para comparar precios, tamaños y platos, y a usar ''than'' con naturalidad al pedir en un restaurante o comprar.', '[{"heading": "Adjetivos cortos: añade -er", "body": "Si el adjetivo tiene una sílaba (o dos terminadas en -y), le añades -er. No uses ''more'' con estos: es el error número uno de los hispanohablantes.", "bullets": ["cheap → cheaper, small → smaller", "big → bigger (dobla la consonante final)", "easy → easier, tasty → tastier (la -y pasa a -i)", "Nunca digas ''more cheap'' ni ''more big''"]}, {"heading": "Adjetivos largos: usa more", "body": "Si el adjetivo tiene dos sílabas o más (y no termina en -y), pones ''more'' delante y el adjetivo no cambia. Es lo típico con palabras de comida y compras.", "bullets": ["expensive → more expensive", "delicious → more delicious", "comfortable → more comfortable", "Irregulares: good → better, bad → worse"]}, {"heading": "''Than'' es la palabra clave", "body": "Para comparar dos cosas, une las dos partes con ''than''. Se pronuncia muy suave, pero escribirlo con ''that'' es un error frecuente.", "bullets": ["This one is cheaper THAN that one", "''That'' significa ''que/ese'', no sirve aquí", "Orden: comparativo + than + la segunda cosa", "Con irregulares igual: better than, worse than"]}]'::jsonb, '[{"en": "This restaurant is cheaper than that one.", "es": "Este restaurante es más barato que aquel.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/c36d5530-bbc5-52cf-a24e-34eeb881b055.mp3"}, {"en": "The fish is more expensive than the chicken.", "es": "El pescado es más caro que el pollo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a1621055-2dc4-5731-a616-9d1987d8795f.mp3"}, {"en": "Can I have a bigger size, please?", "es": "¿Me da una talla más grande, por favor?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/2751390e-da70-5a22-8fb0-bc6c63acef02.mp3"}, {"en": "The service here is better than at the other café.", "es": "El servicio aquí es mejor que en el otro café.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/dc7d6f53-7aa3-5026-9863-584cdd755bde.mp3"}]'::jsonb, '[{"title": "''More cheap'' en vez de ''cheaper''", "body": "Con adjetivos cortos no se usa ''more''. Se dice ''cheaper'', ''smaller'', ''bigger''. Di ''This shirt is cheaper'', no ''This shirt is more cheap''."}, {"title": "Escribir ''that'' en lugar de ''than''", "body": "Suenan parecido, pero solo ''than'' compara. Correcto: ''It is bigger than mine''. Incorrecto: ''It is bigger that mine''."}, {"title": "''More better'' o ''more good''", "body": "''Good'' es irregular: su comparativo es ''better'', sin ''more''. Di ''The pizza is better here'', nunca ''more better''."}, {"title": "Nota cultural: la propina en EE. UU.", "body": "En Estados Unidos la propina se deja aparte de la cuenta: lo normal es un 15-20 % extra. Casi nunca viene incluida, así que se añade al pagar."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta del comparativo.", "options": ["This coffee is cheaper.", "This coffee is more cheap.", "This coffee is cheapest."], "answer": "This coffee is cheaper.", "id": "u10q1"}, {"type": "multiple_choice", "prompt": "¿Cuál es el comparativo correcto de ''expensive''?", "options": ["more expensive", "expensiver", "most expensive"], "answer": "more expensive", "id": "u10q2"}, {"type": "cloze", "prompt": "Completa con la palabra que une la comparación.", "text": "This bag is bigger ___ mine.", "answer": "than", "accepted": ["than"], "id": "u10q3"}, {"type": "cloze", "prompt": "Escribe el comparativo del adjetivo ''good''.", "text": "The dessert here is ___ than the one at the hotel.", "answer": "better", "accepted": ["better"], "id": "u10q4"}, {"type": "multiple_choice", "prompt": "En un restaurante de Estados Unidos, ¿qué es lo normal con la propina?", "options": ["You usually leave 15-20% extra.", "The tip is always included in the check.", "You never leave a tip."], "answer": "You usually leave 15-20% extra.", "id": "u10q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 11, 'A2', 'Personas y descripciones', 'Vas a describir qué hace y qué lleva puesto alguien AHORA MISMO con el presente continuo, y a distinguir los verbos que no lo usan.', '[{"heading": "Ahora mismo: am / is / are + -ing", "body": "Para decir lo que pasa en este momento usas dos piezas: el verbo be (am, is, are) y el verbo principal con -ing. Las dos son obligatorias: sin be no hay frase.", "bullets": ["I am waiting. / He is talking. / They are running.", "Nunca digas «He talking» ni «He is talk».", "Negativo: She is not (isn''t) working.", "Pregunta: Are you listening?"]}, {"heading": "Cómo se escribe y cómo suena el -ing", "body": "El -ing suena nasal, como la n de «banco»: no se pronuncia una g fuerte al final. Al escribir hay tres reglas de ortografía muy frecuentes.", "bullets": ["Quita la -e final: write → writing, take → taking.", "Dobla la consonante: run → running, sit → sitting.", "Lo normal: wear → wearing, talk → talking.", "Suena «-ing», nunca «-in-g» con g dura."]}, {"heading": "Verbos de estado: sin -ing", "body": "Algunos verbos hablan de estados, no de acciones. No describen algo que ocurre y termina, así que van en presente simple aunque hables del momento actual.", "bullets": ["know, like, love, want, need, have (poseer).", "I know the answer. (No: I am knowing.)", "She wants a coffee now. (No: is wanting.)", "Con -ing sí: work, eat, wear, read, talk."]}]'::jsonb, '[{"en": "She is wearing a blue jacket today.", "es": "Ella lleva puesta una chaqueta azul hoy.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f2c16386-1e9f-5f22-b253-7fcab82e6016.mp3"}, {"en": "The tall man with glasses is waiting outside.", "es": "El hombre alto de gafas está esperando afuera.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/159fffca-a79e-5f92-9fe5-5a7ae4049727.mp3"}, {"en": "My sister has long hair, but she likes it short.", "es": "Mi hermana tiene el pelo largo, pero le gusta corto.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/36c22afc-e487-52a3-b7e4-34c983526316.mp3"}, {"en": "They aren''t listening; they are talking about the film.", "es": "No están escuchando; están hablando de la película.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/00f1104d-c753-57fe-82fe-070352c823a2.mp3"}]'::jsonb, '[{"title": "Olvidar el verbo be", "body": "En español dices «Él trabaja ahora», sin auxiliar. En inglés no puedes decir «He working now». Correcto: He is working now."}, {"title": "Poner -ing a los verbos de estado", "body": "Decimos «lo estoy queriendo» o «lo estoy sabiendo», pero en inglés no. No digas «I am wanting a coffee» ni «I am knowing him»: usa I want a coffee / I know him."}, {"title": "Escribir mal el -ing", "body": "Con -e final, la -e desaparece: write → writing. Si la palabra es corta y termina en UNA vocal + UNA consonante, se dobla: run → running, sit → sitting. Ojo: si hay dos vocales no se dobla: rain → raining, wear → wearing."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta para describir lo que pasa ahora mismo.", "options": ["She is wearing a red hat.", "She wearing a red hat.", "She is wear a red hat."], "answer": "She is wearing a red hat.", "id": "u11q1"}, {"type": "multiple_choice", "prompt": "¿Cuál es la forma -ing correcta del verbo write?", "options": ["writing", "writeing", "writting"], "answer": "writing", "id": "u11q2"}, {"type": "multiple_choice", "prompt": "Elige la frase correcta con un verbo de estado.", "options": ["I know his brother.", "I am knowing his brother.", "I knowing his brother."], "answer": "I know his brother.", "id": "u11q3"}, {"type": "cloze", "prompt": "Completa con el verbo be correcto (presente continuo).", "text": "Look! It ___ raining.", "answer": "is", "accepted": ["is", "''s"], "id": "u11q4"}, {"type": "cloze", "prompt": "Completa con la forma -ing del verbo run.", "text": "The children are ___ in the park.", "answer": "running", "accepted": ["running"], "id": "u11q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000001', 12, 'A2', 'Salud, experiencias y consejos', 'Aprende a preguntar por experiencias de vida con ever y never, y a dar consejos con should. Ideal para hablar de salud y del médico.', '[{"heading": "Ever y never: experiencias de vida", "body": "Usamos have/has + participio para hablar de experiencias sin decir cuándo. En preguntas, ''ever'' va entre el sujeto y el participio (Have you ever been…?); en negativo usamos ''never'' sin ''not''.", "bullets": ["Have you ever + participio? = ¿Alguna vez…?", "I have never + participio = Nunca he…", "Con he/she/it usamos ''has''.", "No decimos la fecha exacta aquí."]}, {"heading": "Responder a Have you ever…?", "body": "La respuesta corta usa have/haven''t o has/hasn''t. Si quieres dar detalles con fecha, cambias al pasado simple.", "bullets": ["Yes, I have. / No, I haven''t.", "Yes, she has. / No, he hasn''t.", "Con detalle: I went there last year.", "''Been'' = fue y ya volvió. ''Gone'' = fue y sigue allí."]}, {"heading": "Should para consejos", "body": "Should sirve para aconsejar. Después va el verbo en infinitivo sin ''to'' y no cambia con he, she o it. El negativo es shouldn''t.", "bullets": ["You should rest. = Deberías descansar.", "You shouldn''t work today.", "Should he see a doctor?", "Nunca ''should to'' ni ''shoulds''."]}]'::jsonb, '[{"en": "Have you ever been to London?", "es": "¿Has estado alguna vez en Londres?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/2456cee9-6074-51cd-b674-4694f245373b.mp3"}, {"en": "I have never broken my arm.", "es": "Nunca me he roto el brazo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e1b4d369-b521-562b-8bea-113534d70bb6.mp3"}, {"en": "You should drink more water and rest.", "es": "Deberías beber más agua y descansar.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a312ede3-17e8-59dc-bdb2-bdbca7fcee1a.mp3"}, {"en": "She shouldn''t go to work with a fever.", "es": "Ella no debería ir a trabajar con fiebre.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/28fc3412-8c3e-5364-8224-9770af7f0cd5.mp3"}]'::jsonb, '[{"title": "No uses ''should to''", "body": "Después de should el verbo va sin ''to''. Mal: You should to rest. Bien: You should rest."}, {"title": "''Never'' ya es negativo", "body": "No lo mezcles con ''not''. Mal: I haven''t never tried sushi. Bien: I have never tried sushi."}, {"title": "Should no lleva -s", "body": "Es igual para todas las personas. Mal: He shoulds call the doctor. Bien: He should call the doctor."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la pregunta correcta sobre una experiencia de vida.", "options": ["Have you ever eaten sushi?", "Do you ever eaten sushi?", "Have you ever ate sushi?"], "answer": "Have you ever eaten sushi?", "id": "u12q1"}, {"type": "cloze", "prompt": "Completa el consejo con el modal correcto.", "text": "You ___ see a doctor.", "answer": "should", "accepted": ["should"], "id": "u12q2"}, {"type": "cloze", "prompt": "Completa la frase SIN usar ''not'': nunca he estado en Canadá.", "text": "I have ___ been to Canada.", "answer": "never", "accepted": ["never"], "id": "u12q3"}, {"type": "multiple_choice", "prompt": "Tu amigo tiene fiebre. ¿Qué consejo es correcto?", "options": ["He shouldn''t go out today.", "He shouldn''t to go out today.", "He shoulds not go out today."], "answer": "He shouldn''t go out today.", "id": "u12q4"}, {"type": "cloze", "prompt": "Completa la pregunta: ¿Ha viajado ella alguna vez sola?", "text": "___ she ever travelled alone?", "answer": "Has", "accepted": ["Has"], "id": "u12q5"}]'::jsonb)
on conflict (course_id, unit_order) do update set
  cefr_level = excluded.cefr_level, title = excluded.title,
  summary = excluded.summary, sections = excluded.sections,
  examples = excluded.examples, pitfalls = excluded.pitfalls,
  quiz = excluded.quiz, updated_at = now();

-- ── get_study_theory: la sesión de estudio de un tema, SIN las respuestas ────
create or replace function public.get_study_theory(p_unit_id uuid)
returns jsonb
language plpgsql
security definer
set search_path to 'public'
as $function$
declare uid uuid := auth.uid(); v_unit units%rowtype; v_row study_theory%rowtype;
begin
  if uid is null then raise exception 'auth required'; end if;
  select * into v_unit from units where id = p_unit_id;
  if v_unit.id is null then return null; end if;
  select * into v_row from study_theory
   where course_id = v_unit.course_id and unit_order = v_unit.order_index;
  if v_row.id is null then return null; end if;   -- aún sin teoría rica: E-1 decide
  return jsonb_build_object(
    'unit_order', v_row.unit_order,
    'cefr_level', v_row.cefr_level,
    'title', v_row.title,
    'summary', v_row.summary,
    'sections', v_row.sections,
    'examples', v_row.examples,
    'pitfalls', v_row.pitfalls,
    -- El quiz viaja SIN answer/accepted (el grading es server-side, como todo el
    -- resto del contenido: el cliente nunca ve la respuesta antes de responder).
    'quiz', coalesce((
      select jsonb_agg(jsonb_build_object(
               'id', it ->> 'id', 'type', it ->> 'type',
               'prompt', it ->> 'prompt', 'text', it ->> 'text',
               'options', it -> 'options') order by ord)
      from jsonb_array_elements(v_row.quiz) with ordinality as t(it, ord)), '[]'::jsonb));
end $function$;

-- ── submit_study_quiz: prueba FORMATIVA (sin economía ni dominio) ────────────
-- Califica con jz_grade — el MISMO grader tolerante del resto de la app, que
-- desde mig 177 acepta el conjunto `accepted` (sinónimos/variantes válidas).
-- NO da XP/oro, NO toca user_item_attempts → no altera economía ni certificación.
create or replace function public.submit_study_quiz(p_unit_id uuid, p_answers jsonb)
returns jsonb
language plpgsql
security definer
set search_path to 'public'
as $function$
declare
  uid uuid := auth.uid(); v_unit units%rowtype; v_row study_theory%rowtype;
  v_graded int := 0; v_correct int := 0; v_results jsonb := '[]'::jsonb;
  rec record; v_ok boolean; v_type content_item_type; v_corr jsonb;
begin
  if uid is null then raise exception 'auth required'; end if;
  select * into v_unit from units where id = p_unit_id;
  if v_unit.id is null then raise exception 'not found'; end if;
  select * into v_row from study_theory
   where course_id = v_unit.course_id and unit_order = v_unit.order_index;
  if v_row.id is null then raise exception 'not found'; end if;

  for rec in
    select it ->> 'id' as qid, it ->> 'type' as qtype,
           it ->> 'answer' as qans, coalesce(it -> 'accepted', '[]'::jsonb) as qacc,
           (select a -> 'answer' from jsonb_array_elements(p_answers) a
             where a ->> 'id' = it ->> 'id' limit 1) as given
      from jsonb_array_elements(v_row.quiz) it
  loop
    v_graded := v_graded + 1;
    v_type := rec.qtype::content_item_type;
    v_corr := jsonb_build_object('value', rec.qans, 'accepted', rec.qacc);
    v_ok := rec.given is not null and jz_grade(v_type, v_corr, rec.given);
    if v_ok then v_correct := v_correct + 1; end if;
    v_results := v_results || jsonb_build_object(
      'id', rec.qid, 'correct', coalesce(v_ok, false), 'expected', rec.qans);
  end loop;

  return jsonb_build_object(
    'graded', v_graded, 'correct', v_correct,
    'accuracy', case when v_graded > 0
                     then round(v_correct::numeric / v_graded, 2) else 0 end,
    'passed', v_graded > 0 and v_correct::numeric / v_graded >= 0.6,
    'results', v_results);
end $function$;

